const body = $input.first().json.body;
const message = body.message || body.query || '';
const lower = message.toLowerCase();

let query_type = 'general';
let period = 'current_month';
let category = 'overview';

if (/p&l|profit|loss|income statement/i.test(lower)) query_type = 'pnl';
else if (/revenue|sales|income/i.test(lower)) query_type = 'revenue';
else if (/cost|expense|spend/i.test(lower)) query_type = 'expenses';
else if (/cash flow|runway|balance/i.test(lower)) query_type = 'cashflow';
else if (/anomal|unusual|alert|flag/i.test(lower)) query_type = 'anomalies';
else if (/margin|markup/i.test(lower)) query_type = 'margins';

if (/today/i.test(lower)) period = 'today';
else if (/yesterday/i.test(lower)) period = 'yesterday';
else if (/week/i.test(lower)) period = 'weekly';
else if (/month/i.test(lower)) period = 'monthly';
else if (/quarter/i.test(lower)) period = 'quarterly';

if (/food|ingredient|cogs/i.test(lower)) category = 'food_cost';
else if (/labor|staff|payroll/i.test(lower)) category = 'labor';
else if (/marketing|ads|promotion/i.test(lower)) category = 'marketing';
else if (/delivery|talabat|careem/i.test(lower)) category = 'delivery';
else if (/rent|utilit|overhead/i.test(lower)) category = 'overhead';

return [{
  json: {
    message,
    query_type,
    period,
    category,
    client_id: body.client_id || 'saffron',
    timestamp: new Date().toISOString()
  }
}];

