const response = $input.first().json;
let reply = response.choices?.[0]?.message?.content || response.reply || 'Unable to generate financial analysis.';
reply = reply.replace(/<think>[\s\S]*?<\/think>\s*/g, '').trim();
reply = reply.replace(/\*\*/g, '').replace(/^---$/gm, '').trim();
return [{ json: { reply } }];

